use std::collections::HashMap;

#[derive(Debug)]
pub enum DispatchError {
    BadPayload(String),
    UnknownTask(String),
}

pub struct Worker {
    handlers: HashMap<String, fn(u32) -> u32>,
}

impl Worker {
    pub fn dispatch(&self, task: &str, raw_count: &str) -> Result<u32, DispatchError> {
        let count: u32 = raw_count
            .parse()
            .map_err(|_| DispatchError::BadPayload(raw_count.to_string()))?;
        let handler = self
            .handlers
            .get(task)
            .ok_or_else(|| DispatchError::UnknownTask(task.to_string()))?;
        Ok(handler(count))
    }
}

